import React from "react"
import { graphql } from "gatsby"
import { Breadcrumb, Container, Header, Icon, Item, List, Label, Message } from "semantic-ui-react"

import { Link } from "gatsby"

import Layout from "../components/layout"
import SEO from "../components/seo"

import logo from "../images/progmiscon-logo-64.png"

function Authors({ authors }) {
  return (
    <List horizontal>
    {
    authors.map((author) => (
      <List.Item
        key={`${author.firstName}-${author.lastName}`}
      >
        <span style={{ fontSize: '120%' }}>{author.firstName} <strong>{author.lastName}</strong></span>
      </List.Item>
    ))
    }
    </List>
  );
}

function Abstract({abstract}) {
  return abstract
    //? <Accordion defaultActiveIndex={0} panels={<div>{abstract}</div>} />
    ? <div>{abstract}</div>
    : null;
}

function TypeUnknown({ abstract }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

function ConferencePaper({ abstract, proceedingsTitle }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <strong>{proceedingsTitle}</strong>
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}


function Thesis({ abstract, thesisType, university, place }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <strong>{thesisType} - {university} - {place}</strong>
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

function JournalArticle({ abstract, publication, volume, issue, pages }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <strong>{publication}, Volume {volume}, Issue {issue} {pages ? `, ${pages}` : null}</strong>
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

function Report({ abstract, reportType, reportNumber, seriesTitle }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <strong>{reportType || "Report"}, {reportNumber}, {seriesTitle}</strong>
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

function WebPage({ url, abstract, websiteTitle, accessed }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <a href={url} target="_blank" rel="noreferrer">{websiteTitle}</a> - Last accessed: {accessed}
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

function BookSection({ abstract, bookTitle, publisher, pages }) {
  return (
    <>
      <Item>
        <Item.Content>
          <Item.Description>
            <p>
              <strong>{bookTitle}, {publisher}, {pages}</strong>
            </p>
            <Abstract abstract={abstract} />
          </Item.Description>
        </Item.Content>
      </Item>
    </>
  );
}

const getReferenceComponent = (reference) => {
  if(!reference || !reference.data) {
    return (
      <>
        Reference not found
      </>
    )
  }

  const { itemType } = reference.data

  switch(itemType) {
    case "bookSection":
      return (
        <BookSection
          abstract={reference.data.abstractNote}
          bookTitle={reference.data.bookTitle}
          publisher={reference.data.publisher}
          pages={reference.data.pages}
        />
      )
    case "webpage":
      return (
        <WebPage
          url={reference.data.url}
          abstract={reference.data.abstractNote}
          websiteTitle={reference.data.websiteTitle}
          accessed={reference.data.accessDate}
        />
      )
    case "report": 
      return (
        <Report
          abstract={reference.data.abstractNote}
          reportType={reference.data.reportType}
          reportNumber={reference.data.reportNumber}
          seriesTitle={reference.data.seriesTitle}
        />
      )
    case "thesis": 
      return (
        <Thesis
          abstract={reference.data.abstractNote}
          thesisType={reference.data.thesisType}
          university={reference.data.university}
          place={reference.data.place}
        />
      )
    case "journalArticle": 
      return (
        <JournalArticle
          abstract={reference.data.abstractNote}
          publication={reference.data.publicationTitle}
          volume={reference.data.volume}
          issue={reference.data.issue}
          pages={reference.data.numPages}
        />
      )
    case "conferencePaper": 
      return (
        <ConferencePaper
          abstract={reference.data.abstractNote}
          proceedingsTitle={reference.data.proceedingsTitle}
        />
      )
    default: 
      return (
        <TypeUnknown
          abstract={reference.data.abstractNote}
        />
      )
  }
}

const ReferencePageTemplate = ({ /*pageContext,*/ data }) => {
  // pageContext is given in gatsby-node.js, in createPage({path, component, context})
  //const { citationKey } = pageContext;

  const reference = data.zoteroItems
  const referenceCount = data.misconceptions.edges ? data.misconceptions.edges.length : 0;

  const refEntry = data.refs.edges.filter(edge => edge.node.slug === "references/"+reference.citationKey);

  return (
    <Layout>
      <SEO
        title={reference.citationKey}
      />
      <Container text style={{ marginTop: "100px", marginBottom: "100px" }}>
        <Breadcrumb>
          <Breadcrumb.Section link as={Link} to="/">
            Home
          </Breadcrumb.Section>
          <Breadcrumb.Divider icon="right chevron" />
          <Breadcrumb.Section link as={Link} to="/references">
            References
          </Breadcrumb.Section>
          <Breadcrumb.Divider icon="right chevron" />
          <Breadcrumb.Section active>{reference.citationKey}</Breadcrumb.Section>
        </Breadcrumb>

        <Header as="h1" dividing>
          <Header.Content>
            {reference.data.title}
          </Header.Content>
          <Header.Subheader>
            <Authors authors={reference.data.creators} />
          </Header.Subheader>
        </Header>
        
        <p>{reference.data.parsedDate.substring(0, 4)}</p>

        {getReferenceComponent(reference)}

        {
          reference.data.url
          ? <Message icon info>
              <Icon name="file alternate outline" />
              <Message.Content>
                <Message.Header>Read the Paper</Message.Header>
                <a href={reference.data.url} target="_blank" rel="noreferrer">{reference.data.url}</a>
              </Message.Content>
            </Message>
          : null
        }

        {refEntry.map((edge) => (
          <div key={edge.node.slug}>
            <Header as="h2" dividing>
              <Header.Content>
                Study Information
              </Header.Content>
              <Header.Subheader>
                Manually extracted from the paper by the Progmiscon.org team
              </Header.Subheader>
            </Header>

            <Header as="h3">
              <Header.Content>
                Programming Languages
              </Header.Content>
            </Header>

            <div>
              {edge.node.frontmatter.langs.map(lang => (
                <Label
                  key={lang}
                  color="red"
                >
                { lang }
                </Label>
              ))}
            </div>

            <Header as="h3">
              <Header.Content>
                Method
              </Header.Content>
            </Header>
            <p>{edge.node.frontmatter.method}</p>

            <Header as="h3">
              <Header.Content>
                Subjects
              </Header.Content>
            </Header>
            <p>{edge.node.frontmatter.subjects}</p>

            {
              edge.node.frontmatter.phenomenonKinds ? (
                <>
                  <Header as="h3">
                    <Header.Content>
                      Phenomena Studied
                    </Header.Content>
                  </Header>
                  <List selection>
                    {
                      edge.node.frontmatter.phenomenonKinds.map(phenomenon => (
                        <List.Item key={phenomenon.name}>
                          <List.Icon className="eye" size='large' verticalAlign='middle' />
                          <List.Content>
                            <List.Header>{phenomenon.name}</List.Header>
                            {phenomenon.description}
                          </List.Content>
                        </List.Item>
                      ))
                    }
                  </List>
                </>
              ) : null
            }

            <Header as="h3">
              <Header.Content>
                Artifact
              </Header.Content>
            </Header>
            {
              edge.node.frontmatter.artifact
              ? <a href={edge.node.frontmatter.artifact}>{edge.node.frontmatter.artifact}</a>
              : <span>We are not aware of an artifact supporting this paper.</span>
            }
          </div>
        ))}

        <Header as="h2" dividing>
          <Header.Content>
            Related Misconceptions
          </Header.Content>
          <Header.Subheader>
            Referenced by {referenceCount} Misconception{referenceCount === 1 ? "" : "s"}
          </Header.Subheader>
        </Header>

        <List selection verticalAlign="middle">
          {data.misconceptions.edges.map((edge) => (
            <List.Item as={Link} to={`/${edge.node.slug}`} key={edge.node.slug}>
              <img
                className="ui image"
                alt="Misconception"
                width="20"
                src={logo}
              />
              <List.Content>
                <List.Header>
                  {/* color this like a link, without producing a nested a element */}
                  <span style={{ color: "#4183c4" }}>{edge.node.fields.name}</span>
                  <span> &mdash; {edge.node.fields.pl}</span>
                </List.Header>
                {edge.node.frontmatter.shortDescription}
              </List.Content>
            </List.Item>
          ))}
          {data.misconceptions.edges.length ? "" : 
            <List.Item>No referenced misconceptions for this publication</List.Item>
          }
        </List>

      </Container>
    </Layout>
  )
}

export default ReferencePageTemplate

export const query = graphql`
  query($citationKey: String!) {
    zoteroItems(citationKey: {eq: $citationKey}) {
      citationKey
      data {
        key
        version
        itemType
        title
        abstractNote
        date
        proceedingsTitle
        conferenceName
        thesisType
        university
        place
        publisher
        volume
        pages
        series
        language
        DOI
        ISBN
        shortTitle
        url
        accessDate(formatString: "YYYY.MM.DD")
        archive
        archiveLocation
        libraryCatalog
        callNumber
        rights
        extra
        dateAdded
        dateModified
        reportNumber
        reportType
        seriesTitle
        institution
        publicationTitle
        issue
        seriesText
        journalAbbreviation
        ISSN
        bookTitle
        seriesNumber
        numberOfVolumes
        edition
        creators {
          creatorType
          firstName
          lastName
        }
        tags {
          tag
          type
        }
        parsedDate,
        creatorSummary,
      }
    }
    misconceptions: allMdx(
      filter: {frontmatter: {references: {elemMatch: {citationKey: {eq: $citationKey}}}}}
      sort: { fields: fields___name, order: ASC }
    ) {
      totalCount
      edges {
        node {
          slug
          fields {
            slug
            name
            pl
          }
          frontmatter {
            shortDescription
          }
        }
      }
    }
    refs: allMdx(filter: {frontmatter: {type: {eq: "ref"}}}) {
      edges {
        node {
          id
          slug
          frontmatter {
            langs
            method
            subjects
            artifact
            phenomenonKinds {
              name
              description
              phenomena {
                id
                name
                observations {
                  measure
                  count
                  maxCount
                }
              }
            }
          }
          fields {
            slug
            name
            pl
          }
        }
      }
    }
  }
`
